#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Function to convert hex string to binary data
void hexStringToBytes(const char* hexString, unsigned char* buffer, size_t* length) {
    size_t strLength = strlen(hexString);
    *length = strLength / 2; // Each byte is represented by 2 hex characters
    for (size_t i = 0; i < *length; i++) {
        sscanf(hexString + 2 * i, "%2hhx", &buffer[i]);
    }
}

// Function to write or append binary data to a file
void writeToFile(const char* filename, const unsigned char* data, size_t dataLength, int append) {
    FILE* file = fopen(filename, append ? "ab" : "wb");
    if (file == NULL) {
        perror("Error opening file");
        exit(EXIT_FAILURE);
    }
    fwrite(data, 1, dataLength, file);
    fclose(file);
}

int main() {
    // Example hex strings
    unsigned char buffer[9999];
    size_t length;
    char* hexString1 = "";
    
    
    
    hexStringToBytes(hexString1, buffer, &length);
    writeToFile("output.bin", buffer, length, 0); // 0 = write mode
    
    hexString1 = "";

    hexStringToBytes(hexString1, buffer, &length);
    writeToFile("output.bin", buffer, length, 1); // 1 = append mode

    hexString1 = "";
    hexStringToBytes(hexString1, buffer, &length);
    writeToFile("output.bin", buffer, length, 1); // 1 = append mode


    hexString1 = "";
    hexStringToBytes(hexString1, buffer, &length);
    writeToFile("output.bin", buffer, length, 1); // 1 = append mode



    hexString1 = "";
    hexStringToBytes(hexString1, buffer, &length);
    writeToFile("output.bin", buffer, length, 1); // 1 = append mode



    hexString1 = "";
    hexStringToBytes(hexString1, buffer, &length);
    writeToFile("output.bin", buffer, length, 1); // 1 = append mode

    

    return 0;
}

